/* eslint-disable import/no-extraneous-dependencies */
const { statsd } = require('frontend-statsd/internal');
const env = require('frontend-env');
const { encodeStringToBase32 } = require('@andes/common/build/utils/encodeBase32');
const transformToKebabCase = require('@andes/common/build/utils/transformToKebabCase');

const statName = 'andes.frontend_andes_ui.customization';
const initialValue = 1;
const sampleRate = 0.25;

/** @typedef {import('./metrics').CustomizationData} CustomizationData */

/** @param {CustomizationData} data */
const trackCustomization = ({ type, ...other }) => {
  statsd.increment(statName, initialValue, sampleRate, {
    application: env.APPLICATION,
    platform: env.PLATFORM || '',
    customizationType: type,
    ...other,
  }, () => {});
};

/** @type {Record<string, import('./metrics.d.ts').CustomizationType>} */
const CUSTOMIZATION_TYPE = {
  CUSTOM: 'custom',
  HEADLESS: 'headless',
  STYLE_OVERRIDES: 'styleOverrides',
  TOKENS: 'tokens',
  SLOTS: 'slots',
};

const MAX_TAG_LENGTH = 200;

/**
 * Shortens the properties of an object to fit within a specified maximum length
 *
 * @param {Record<string, string>} obj
 * @param {number} maxLength
 */
const shortenObjectToMaxLength = (obj = {}, maxLength = 0) => {
  const shortenObject = /** @type {Record<string, string>} */ ({});
  const objectString = JSON.stringify(obj);
  const objectBase32 = encodeStringToBase32(objectString);

  if (objectBase32.length <= maxLength) {
    return obj;
  }

  let accumulatedCharacters = 0;
  // eslint-disable-next-line no-restricted-syntax
  for (const [key, value] of Object.entries(obj)) {
    const stringProperty = `"${key}":${JSON.stringify(value)},`;

    if (accumulatedCharacters + stringProperty.length <= maxLength) {
      shortenObject[key] = value;
      accumulatedCharacters += stringProperty.length;
    } else {
      break;
    }
  }

  return shortenObject;
};

/**
 * Encode the values of an object in Base32
 *
 * @param {Record<string, string>} obj
 */
const parseObjectValuesToBase32 = (obj = {}) => Object.entries(obj)
  .reduce((acc, [key, value]) => {
    acc[key] = encodeStringToBase32(value);
    return acc;
  }, /** @type {Record<string, string>} */ ({}));

/**
 * Creates an object with methods to process and record various types of customization metrics.
 *
 * @param {(data?: CustomizationData) => void} tracker - Tracking function used to record metrics.
 * @returns {Object} An object with methods to send different types of customization metrics:
 *   - `sendCustom`: Processes and records custom metrics.
 *   - `sendHeadless`: Processes and records metrics for headless components.
 *   - `sendStyleOverrides`: Processes and records style override metrics.
 *   - `sendTokens`: Processes and records 'tokens' metrics.
 */
const senderMetrics = (tracker) => {
  /**
   * Process data and record 'custom' metrics.
   *
   * @type {import('./metrics').SendCustom}
   */
  const sendCustom = ({ component, details = {} }) => {
    const tagKey = 'custom-properties';
    const properties = shortenObjectToMaxLength(details, MAX_TAG_LENGTH - tagKey.length);
    const propertiesString = JSON.stringify(properties);
    const propertiesBase32 = encodeStringToBase32(propertiesString);
    const hasMoreProperties = Object.keys(properties).length < Object.keys(details).length;
    const data = { [tagKey]: propertiesBase32, 'more-properties': hasMoreProperties };

    tracker?.({
      type: CUSTOMIZATION_TYPE.CUSTOM,
      // @ts-expect-error
      component: typeof component === 'string' ? transformToKebabCase(component) : undefined,
      ...data,
    });
  };

  /**
   * Processes and records metrics for headless components.
   *
   * @type {import('./metrics').SendHeadless}
   */
  const sendHeadless = (componentName) => (componentProps) => {
    const shouldSendHeadlessComponentMetric = 'extend' in componentProps && componentProps.extend;

    if (shouldSendHeadlessComponentMetric) {
      tracker?.({
        type: CUSTOMIZATION_TYPE.HEADLESS,
        component: componentName,
      });
    }
  };

  /**
   * Processes and records metrics for slots components.
   *
   * @type {import('./metrics').SendSlots}
   */
  const sendSlots = (componentName, slotConditionFn) => (componentProps) => {
    const shouldSlotComponentMetric = typeof slotConditionFn === 'function'
      ? slotConditionFn(componentProps)
      : false;

    if (shouldSlotComponentMetric) {
      tracker?.({ type: CUSTOMIZATION_TYPE.SLOTS, component: componentName });
    }
  };

  /**
   * Process data and record 'styleOverrides' metrics.
   *
   * @type {import('./metrics').SendStyleOverrides}
   */
  const sendStyleOverrides = ({ component }) => {
    tracker?.({
      type: CUSTOMIZATION_TYPE.STYLE_OVERRIDES,
      // @ts-expect-error
      component: transformToKebabCase(component),
    });
  };

  /**
   * Process data and record 'tokens' metrics.
   *
   * @type {import('./metrics').SendTokens}
   */
  const sendTokens = ({ details = {} }) => {
    const tokensStringToMaxLength = Object.entries(details).reduce((acc, [key, value]) => {
      acc[key] = typeof value === 'string'
        ? value.slice(0, Math.max(MAX_TAG_LENGTH - key.length, 0))
        : value;
      return acc;
    }, /** @type {Record<string, string>} */ ({}));
    const tokens = parseObjectValuesToBase32(tokensStringToMaxLength);
    tracker?.({
      type: CUSTOMIZATION_TYPE.TOKENS,
      ...tokens,
    });
  };

  return { sendCustom, sendHeadless, sendSlots, sendStyleOverrides, sendTokens };
};

module.exports = {
  trackCustomization,
  senderMetrics,
};
